/* ════════════════════════════════════════════════════
   PENDING BOOKINGS PAGE
════════════════════════════════════════════════════ */

function PendingPage({ t, lang, services, bookings, isAdmin }) {
  const BRANCH_NAMES = { 0: "Lahug (Salinas Premier)", 1: "Emall (2nd Floor)" };

  // Sort by submittedAt desc (most recent first), fallback to date field
  const sorted = [...bookings].sort((a, b) => {
    const ta = a.submittedAt?.toDate?.()?.getTime?.() ?? 0;
    const tb = b.submittedAt?.toDate?.()?.getTime?.() ?? 0;
    return tb - ta;
  });

  const formatSubmittedAt = (ts) => {
    if (!ts?.toDate) return "—";
    return ts.toDate().toLocaleString(lang === "zh" ? "zh-TW" : "en-US", {
      month: "short", day: "numeric", year: "numeric",
      hour: "2-digit", minute: "2-digit",
    });
  };

  const sourceLabel = (source) => {
    if (source === "guest") return t("sourceGuest");
    return t("sourceAdmin");
  };

  const sourceBadge = (source) => source === "guest"
    ? "bg-sky-100 text-sky-600"
    : "bg-stone-100 text-stone-500";

  return (
    <div>
      <h1
        className="font-display text-2xl md:text-3xl font-light text-stone-800 mb-5"
        dangerouslySetInnerHTML={{ __html: t("pendingTitle") }}
      />

      {sorted.length === 0 ? (
        <div className="bg-white border border-stone-200 rounded-xl p-8 text-center text-stone-400 text-sm shadow-sm">
          {t("pendingEmpty")}
        </div>
      ) : (
        <div className="space-y-3">
          {sorted.map((b) => (
            <div key={b.id} className="bg-white border border-stone-200 rounded-xl p-4 shadow-sm">
              <div className="flex items-start justify-between gap-3 flex-wrap">
                <div className="min-w-0 flex-1">
                  {/* Name + source badge */}
                  <div className="flex items-center gap-2 flex-wrap mb-0.5">
                    <span className="font-semibold text-stone-800 text-sm">{b.name}</span>
                    <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full ${sourceBadge(b.source)}`}>
                      {sourceLabel(b.source)}
                    </span>
                  </div>

                  {/* Date/time & branch */}
                  <div className="text-xs text-stone-500 mb-2">
                    {BRANCH_NAMES[b.branch] ?? "—"} · {b.date} {b.time}
                  </div>

                  {/* Details grid */}
                  <div className="grid sm:grid-cols-2 gap-x-6 gap-y-0.5">
                    {[
                      [t("phone"), b.phone],
                      ["FB/IG", b.social],
                      [t("guestContactVia"), b.contactVia],
                      [t("guestPayment"), b.payment],
                      [t("stylist"), b.staff],
                    ].filter(([, v]) => v).map(([label, val]) => (
                      <div key={label} className="text-xs text-stone-600">
                        <span className="font-medium text-stone-400">{label}: </span>{val}
                      </div>
                    ))}
                  </div>

                  {/* Services */}
                  {b.serviceIds?.length > 0 && (
                    <div className="mt-2">
                      <span className="text-xs font-medium text-stone-400">{t("service")}: </span>
                      <ServiceCheckboxPicker services={services} lang={lang} selected={b.serviceIds} onChange={() => {}} readOnly />
                    </div>
                  )}

                  {/* Submitted at */}
                  <div className="text-[11px] text-stone-400 mt-2 flex items-center gap-1">
                    <Clock size={11} />
                    {t("submittedAt")}: {formatSubmittedAt(b.submittedAt)}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ════════════════════════════════════════════════════
   ACCOUNTS PAGE (admin only)
════════════════════════════════════════════════════ */

function AccountsPage({ t, lang, accounts, onSave, onDelete }) {
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({ username: "", password: "", displayName: "", role: "staff", canApprove: false });
  const setF = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const openNew = () => {
    setEditing("new");
    setForm({ username: "", password: "", displayName: "", role: "staff", canApprove: false });
  };
  const openEdit = (a) => {
    setEditing(a.id);
    setForm({ username: a.username, password: a.password, displayName: a.displayName || "", role: a.role, canApprove: !!a.canApprove });
  };
  const save = async () => {
    const ok = await onSave(form, editing === "new" ? null : editing);
    if (ok) setEditing(null);
  };

  return (
    <div>
      <h1 className="font-display text-2xl md:text-3xl font-light text-stone-800 mb-5"
        dangerouslySetInnerHTML={{ __html: t("accountsTitle") }} />

      {/* Add button */}
      <div className="flex justify-end mb-4">
        <button type="button" onClick={openNew} className="flex items-center gap-1.5 bg-rose-400 hover:bg-rose-500 text-white text-sm font-medium px-4 py-2 rounded-lg transition">
          <Plus size={15} /> {t("addAccount")}
        </button>
      </div>

      {/* Inline form */}
      {editing && (
        <div className="bg-white border border-rose-200 rounded-xl p-5 mb-5 shadow-sm">
          <div className="text-sm font-semibold text-stone-700 mb-4">{editing === "new" ? t("addAccount") : t("saveAccount")}</div>
          <div className="grid sm:grid-cols-2 gap-4">
            <Field label={t("accountUsername")}>
              <input value={form.username} onChange={(e) => setF("username", e.target.value)} className="input" disabled={editing !== "new"} />
            </Field>
            <Field label={t("accountPassword")}>
              <input value={form.password} onChange={(e) => setF("password", e.target.value)} className="input" type="text" />
            </Field>
            <Field label={t("accountDisplayName")}>
              <input value={form.displayName} onChange={(e) => setF("displayName", e.target.value)} className="input" />
            </Field>
            <Field label={t("accountRole")}>
              <select value={form.role} onChange={(e) => setF("role", e.target.value)} className="input">
                <option value="admin">{t("roleAdmin")}</option>
                <option value="staff">{t("roleStaff")}</option>
              </select>
            </Field>
          </div>
          <label className="flex items-center gap-2 mt-3 cursor-pointer">
            <input type="checkbox" checked={form.canApprove} onChange={(e) => setF("canApprove", e.target.checked)} className="w-4 h-4 accent-rose-400" />
            <span className="text-sm text-stone-600">{t("accountCanApprove")}</span>
          </label>
          <div className="flex gap-2 mt-4">
            <button type="button" onClick={save} className="bg-rose-400 hover:bg-rose-500 text-white text-sm font-medium px-4 py-2 rounded-lg transition">{t("saveAccount")}</button>
            <button type="button" onClick={() => setEditing(null)} className="text-sm text-stone-500 border border-stone-200 px-4 py-2 rounded-lg transition">{t("cancel")}</button>
          </div>
          <style>{`.input { padding:9px 12px; border:1px solid #E7E5E4; border-radius:8px; font-size:13px; background:#FAFAF9; outline:none; width:100%; transition:border-color .15s; } .input:focus { border-color:#FB7185; background:white; } .input:disabled { opacity:0.5; cursor:not-allowed; }`}</style>
        </div>
      )}

      {/* Account list */}
      {accounts.length === 0 ? (
        <div className="text-sm text-stone-400 text-center py-8">{t("noAccounts")}</div>
      ) : (
        <div className="space-y-2">
          {accounts.map((a) => (
            <div key={a.id} className="bg-white border border-stone-200 rounded-xl px-4 py-3 shadow-sm flex items-center justify-between gap-3">
              <div>
                <div className="text-sm font-semibold text-stone-800">{a.displayName || a.username} <span className="text-stone-400 font-normal">@{a.username}</span></div>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full ${a.role === "admin" ? "bg-rose-100 text-rose-500" : "bg-amber-100 text-amber-600"}`}>
                    {a.role === "admin" ? t("roleAdmin") : t("roleStaff")}
                  </span>
                  {a.canApprove && <span className="text-[10px] text-green-600 bg-green-50 px-2 py-0.5 rounded-full">{t("accountCanApprove")}</span>}
                </div>
              </div>
              <div className="flex gap-2">
                <button type="button" onClick={() => openEdit(a)} className="text-stone-400 hover:text-rose-400 transition p-1"><Pencil size={15} /></button>
                <button type="button" onClick={() => onDelete(a.id)} className="text-stone-400 hover:text-rose-500 transition p-1"><Trash2 size={15} /></button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ════════════════════════════════════════════════════
   INVENTORY PAGE
   Visible to both admin (editable) and staff (read-only).
   - Compact grid so 150–180 items are scannable at a glance
   - Card order: Brand → Item No. → Qty
   - Optional grouping / filtering by brand
   - Search box to jump to a specific item no.
   - Inline qty +/- and click-to-edit for admins
   - "Paste Update" lets admins bulk-import/update straight from
     an Excel copy: "Item No.<tab>Q'ty" (2 columns), or
     "Brand<tab>Item No.<tab>Q'ty" (3 columns) when they also
     want to set/refresh the brand at the same time
   - "Usage Report" (admin only) queries the inventoryMovements
     log by date range — see architecture note on saveInventoryItem
     / bulkUpsertInventory / logInventoryMovement in AppInner
════════════════════════════════════════════════════ */

function InventoryPage({
  t, lang, isAdmin, inventory, lowStockThreshold,
  onSaveThreshold, onSaveItem, onDeleteItem, onBulkUpsert, showToast,
}) {
  const [search, setSearch] = useState("");
  const [sortLowFirst, setSortLowFirst] = useState(false);
  const [brandFilter, setBrandFilter] = useState("");
  const [groupByBrand, setGroupByBrand] = useState(true);
  const [showPasteModal, setShowPasteModal] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);
  const [newBrand, setNewBrand] = useState("");
  const [newItemNo, setNewItemNo] = useState("");
  const [newQty, setNewQty] = useState("");
  const [editingId, setEditingId] = useState(null);
  const [editQty, setEditQty] = useState("");
  const [editingBrandId, setEditingBrandId] = useState(null);
  const [editBrand, setEditBrand] = useState("");
  const [thresholdDraft, setThresholdDraft] = useState(lowStockThreshold ?? 10);

  useEffect(() => { setThresholdDraft(lowStockThreshold ?? 10); }, [lowStockThreshold]);

  const threshold = Number(lowStockThreshold ?? 10);

  const brandList = useMemo(() => {
    const set = new Set(inventory.map((i) => (i.brand || "").trim()).filter(Boolean));
    return [...set].sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: "base" }));
  }, [inventory]);

  const filtered = useMemo(() => {
    let list = inventory;
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter((i) => (i.itemNo || "").toLowerCase().includes(q) || (i.brand || "").toLowerCase().includes(q));
    }
    if (brandFilter) list = list.filter((i) => (i.brand || "") === brandFilter);
    return [...list].sort((a, b) => {
      if (sortLowFirst) return (Number(a.qty) || 0) - (Number(b.qty) || 0);
      return (a.itemNo || "").localeCompare(b.itemNo || "", undefined, { numeric: true, sensitivity: "base" });
    });
  }, [inventory, search, brandFilter, sortLowFirst]);

  // When grouping, cluster the already-sorted/filtered list under brand headers.
  const grouped = useMemo(() => {
    if (!groupByBrand) return [{ brand: null, items: filtered }];
    const map = new Map();
    filtered.forEach((item) => {
      const key = (item.brand || "").trim() || t("inventoryNoBrand");
      if (!map.has(key)) map.set(key, []);
      map.get(key).push(item);
    });
    return [...map.entries()]
      .sort((a, b) => a[0].localeCompare(b[0], undefined, { numeric: true, sensitivity: "base" }))
      .map(([brand, items]) => ({ brand, items }));
  }, [filtered, groupByBrand, t]);

  const totalQty = useMemo(() => inventory.reduce((sum, i) => sum + (Number(i.qty) || 0), 0), [inventory]);
  const lowCount = useMemo(() => inventory.filter((i) => (Number(i.qty) || 0) <= threshold).length, [inventory, threshold]);

  const startEdit = (item) => { setEditingId(item.id); setEditQty(String(item.qty ?? "")); };
  const commitEdit = (item) => {
    onSaveItem(item.itemNo, editQty === "" ? 0 : Number(editQty), item.brand);
    setEditingId(null);
  };
  const bump = (item, delta) => {
    const next = Math.max(0, (Number(item.qty) || 0) + delta);
    onSaveItem(item.itemNo, next, item.brand, "bump");
  };
  const startEditBrand = (item) => { setEditingBrandId(item.id); setEditBrand(item.brand || ""); };
  const commitBrand = (item) => {
    onSaveItem(item.itemNo, item.qty, editBrand.trim());
    setEditingBrandId(null);
  };
  const handleAddSubmit = () => {
    if (!newItemNo.trim()) { showToast(t("inventoryItemNoRequired"), "warn"); return; }
    onSaveItem(newItemNo, newQty === "" ? 0 : Number(newQty), newBrand.trim());
    setNewBrand(""); setNewItemNo(""); setNewQty(""); setShowAddForm(false);
  };

  const renderCard = (item) => {
    const low = (Number(item.qty) || 0) <= threshold;
    const editing = editingId === item.id;
    const editingBrand = editingBrandId === item.id;
    return (
      <div key={item.id}
        className={`rounded-lg border px-3 py-2.5 flex flex-col gap-1.5 ${low ? "bg-rose-50 border-rose-200" : "bg-white border-stone-200"}`}>
        {/* Brand — shown first per card layout order */}
        {editingBrand ? (
          <input
            autoFocus value={editBrand} onChange={(e) => setEditBrand(e.target.value)}
            onBlur={() => commitBrand(item)}
            onKeyDown={(e) => { if (e.key === "Enter") commitBrand(item); if (e.key === "Escape") setEditingBrandId(null); }}
            className="w-full px-1.5 py-0.5 border border-rose-300 rounded text-[11px] outline-none"
            placeholder={t("inventoryBrand")}
          />
        ) : (
          <span
            onClick={() => isAdmin && startEditBrand(item)}
            className={`text-[11px] font-semibold uppercase tracking-wide truncate ${isAdmin ? "cursor-pointer hover:text-rose-500" : ""} ${item.brand ? "text-stone-500" : "text-stone-300 italic"}`}
            title={item.brand || t("inventoryNoBrand")}
          >
            {item.brand || t("inventoryNoBrand")}
          </span>
        )}

        {/* Item No. */}
        <div className="flex items-center justify-between gap-1">
          <span className="text-xs font-semibold text-stone-700 truncate" title={item.itemNo}>{item.itemNo}</span>
          {isAdmin && (
            <button type="button" onClick={() => onDeleteItem(item.id)} className="text-stone-300 hover:text-rose-500 transition flex-shrink-0">
              <X size={12} />
            </button>
          )}
        </div>

        {/* Qty */}
        {editing ? (
          <input
            autoFocus type="number" value={editQty}
            onChange={(e) => setEditQty(e.target.value)}
            onBlur={() => commitEdit(item)}
            onKeyDown={(e) => { if (e.key === "Enter") commitEdit(item); if (e.key === "Escape") setEditingId(null); }}
            className="w-full px-1.5 py-1 border border-rose-300 rounded text-sm outline-none"
          />
        ) : isAdmin ? (
          <div className="flex items-center justify-between gap-1">
            <button type="button" onClick={() => bump(item, -1)} className="w-6 h-6 flex items-center justify-center rounded bg-stone-100 hover:bg-stone-200 text-stone-500 text-sm font-bold">−</button>
            <span onClick={() => startEdit(item)}
              className={`text-sm font-bold cursor-pointer ${low ? "text-rose-500" : "text-stone-800"}`}>
              {item.qty ?? 0}
            </span>
            <button type="button" onClick={() => bump(item, 1)} className="w-6 h-6 flex items-center justify-center rounded bg-stone-100 hover:bg-stone-200 text-stone-500 text-sm font-bold">+</button>
          </div>
        ) : (
          <span className={`text-sm font-bold ${low ? "text-rose-500" : "text-stone-800"}`}>{item.qty ?? 0}</span>
        )}
      </div>
    );
  };

  return (
    <div className="max-w-6xl">
      <div className="flex items-center justify-between flex-wrap gap-3 mb-5">
        <h1 className="font-display text-2xl font-light text-stone-800" dangerouslySetInnerHTML={{ __html: t("inventoryTitle") }} />
        {isAdmin && (
          <div className="flex items-center gap-2">
            <button type="button" onClick={() => setShowAddForm((v) => !v)}
              className="flex items-center gap-1.5 text-sm font-medium border border-stone-200 hover:border-rose-300 text-stone-600 hover:text-rose-500 px-3 py-2 rounded-lg transition">
              <Plus size={15} /> {t("inventoryAddItem")}
            </button>
            <button type="button" onClick={() => setShowPasteModal(true)}
              className="flex items-center gap-1.5 text-sm font-medium bg-rose-400 hover:bg-rose-500 text-white px-3 py-2 rounded-lg transition">
              <Upload size={15} /> {t("inventoryPasteUpdate")}
            </button>
          </div>
        )}
      </div>

      {!isAdmin && (
        <div className="text-xs text-stone-400 bg-stone-50 border border-stone-200 rounded-lg px-3 py-2 mb-4">
          {t("inventoryReadonlyNotice")}
        </div>
      )}

      {/* stats */}
      <div className="grid grid-cols-3 gap-3 mb-4">
        <div className="bg-white border border-stone-200 rounded-xl px-4 py-3 shadow-sm">
          <div className="text-[11px] text-stone-400 font-medium">{t("inventoryTotalItems")}</div>
          <div className="text-xl font-semibold text-stone-800">{inventory.length}</div>
        </div>
        <div className="bg-white border border-stone-200 rounded-xl px-4 py-3 shadow-sm">
          <div className="text-[11px] text-stone-400 font-medium">{t("inventoryTotalQty")}</div>
          <div className="text-xl font-semibold text-stone-800">{totalQty}</div>
        </div>
        <div className={`rounded-xl px-4 py-3 shadow-sm border ${lowCount > 0 ? "bg-rose-50 border-rose-200" : "bg-white border-stone-200"}`}>
          <div className="text-[11px] text-stone-400 font-medium">{t("inventoryLowStock")}</div>
          <div className={`text-xl font-semibold ${lowCount > 0 ? "text-rose-500" : "text-stone-800"}`}>{lowCount}</div>
        </div>
      </div>

      {showAddForm && isAdmin && (
        <div className="flex flex-wrap items-end gap-2 bg-stone-50 border border-stone-200 rounded-xl p-3 mb-4">
          <GField label={t("inventoryBrand")}>
            <input value={newBrand} onChange={(e) => setNewBrand(e.target.value)} className="ginput" placeholder="e.g. OPI" />
          </GField>
          <GField label={t("inventoryItemNo")}>
            <input value={newItemNo} onChange={(e) => setNewItemNo(e.target.value)} className="ginput" placeholder="A001" />
          </GField>
          <GField label={t("inventoryQty")}>
            <input type="number" value={newQty} onChange={(e) => setNewQty(e.target.value)} className="ginput" placeholder="0" />
          </GField>
          <button type="button" onClick={handleAddSubmit} className="text-sm font-medium bg-rose-400 hover:bg-rose-500 text-white px-4 py-2.5 rounded-lg transition">{t("save")}</button>
          <button type="button" onClick={() => setShowAddForm(false)} className="text-sm font-medium text-stone-500 border border-stone-200 px-4 py-2.5 rounded-lg transition">{t("cancel")}</button>
          <style>{`.ginput { padding:9px 12px; border:1px solid #E7E5E4; border-radius:8px; font-size:13px; background:#FAFAF9; outline:none; transition:border-color .15s; } .ginput:focus { border-color:#FB7185; background:white; }`}</style>
        </div>
      )}

      {/* search + brand filter + sort + threshold */}
      <div className="flex flex-wrap items-center gap-3 mb-4">
        <div className="relative flex-1 min-w-[180px]">
          <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
          <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder={t("inventorySearch")}
            className="w-full pl-9 pr-3 py-2 border border-stone-200 rounded-lg text-sm bg-white outline-none focus:border-rose-300" />
        </div>
        <select value={brandFilter} onChange={(e) => setBrandFilter(e.target.value)}
          className="text-xs font-medium px-3 py-2 rounded-lg border border-stone-200 bg-white text-stone-600 outline-none focus:border-rose-300">
          <option value="">{t("inventoryAllBrands")}</option>
          {brandList.map((b) => <option key={b} value={b}>{b}</option>)}
        </select>
        <button type="button" onClick={() => setGroupByBrand((v) => !v)}
          className={`text-xs font-medium px-3 py-2 rounded-lg border transition ${groupByBrand ? "bg-rose-400 text-white border-rose-400" : "border-stone-200 text-stone-500 hover:border-rose-300"}`}>
          {t("inventoryGroupByBrand")}
        </button>
        <button type="button" onClick={() => setSortLowFirst((v) => !v)}
          className={`text-xs font-medium px-3 py-2 rounded-lg border transition ${sortLowFirst ? "bg-rose-400 text-white border-rose-400" : "border-stone-200 text-stone-500 hover:border-rose-300"}`}>
          {t("inventorySortLow")}
        </button>
        {isAdmin && (
          <div className="flex items-center gap-1.5 text-xs text-stone-500">
            <span>{t("inventoryLowStockThreshold")}</span>
            <input
              type="number"
              value={thresholdDraft}
              onChange={(e) => setThresholdDraft(e.target.value)}
              onBlur={() => onSaveThreshold(thresholdDraft)}
              className="w-16 px-2 py-1.5 border border-stone-200 rounded-lg text-xs bg-white outline-none focus:border-rose-300"
            />
          </div>
        )}
      </div>

      {/* grid — dense so 150+ items stay scannable, grouped by brand */}
      {filtered.length === 0 ? (
        <div className="text-sm text-stone-400 py-10 text-center">{t("inventoryEmpty")}</div>
      ) : (
        <div className="space-y-5">
          {grouped.map((group) => (
            <div key={group.brand || "__all__"}>
              {group.brand && (
                <div className="text-[11px] font-bold tracking-widest uppercase text-stone-400 px-1 pb-1.5 border-b border-stone-100 mb-2">
                  {group.brand} <span className="font-medium normal-case text-stone-300">· {group.items.length}</span>
                </div>
              )}
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-2">
                {group.items.map(renderCard)}
              </div>
            </div>
          ))}
        </div>
      )}

      {isAdmin && (
        <InventoryUsageReport t={t} lang={lang} />
      )}

      {showPasteModal && isAdmin && (
        <InventoryPasteModal t={t} lang={lang} onClose={() => setShowPasteModal(false)} onConfirm={onBulkUpsert} />
      )}
    </div>
  );
}

/* ────────────────────────────────────────────────────
   INVENTORY PASTE-UPDATE MODAL
   Accepts a raw Excel copy-paste. Two formats are both
   auto-detected line-by-line:
     "Item No.<TAB>Q'ty"                 → 2 columns
     "Brand<TAB>Item No.<TAB>Q'ty"       → 3 columns
   A stray header row (text in the Q'ty column) is
   automatically skipped since it won't parse as a number.
──────────────────────────────────────────────────── */

function InventoryPasteModal({ t, lang, onClose, onConfirm }) {
  const [text, setText] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const parsed = useMemo(() => {
    const lines = text.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
    const rows = [];
    let invalid = 0;
    lines.forEach((line) => {
      let parts = line.split("\t");
      if (parts.length < 2) parts = line.split(/,|\s{2,}/);
      if (parts.length < 2) parts = line.split(/\s+/);
      if (parts.length < 2) { invalid++; return; }

      const qtyRaw = parts[parts.length - 1].trim().replace(/,/g, "");
      const qty = Number(qtyRaw);

      if (parts.length >= 3) {
        // Brand / Item No. / Q'ty
        const brand = parts[0].trim();
        const itemNo = parts.slice(1, -1).join(" ").trim();
        if (!itemNo || Number.isNaN(qty)) { invalid++; return; }
        rows.push({ brand, itemNo, qty });
      } else {
        // Item No. / Q'ty
        const itemNo = parts[0].trim();
        if (!itemNo || Number.isNaN(qty)) { invalid++; return; }
        rows.push({ itemNo, qty });
      }
    });
    return { rows, invalid };
  }, [text]);

  const handleConfirm = async () => {
    if (!parsed.rows.length) return;
    setSubmitting(true);
    await onConfirm(parsed.rows);
    setSubmitting(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="bg-white rounded-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto shadow-2xl" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between px-6 py-4 border-b border-stone-100">
          <h2 className="font-display text-xl font-light text-stone-800">{t("inventoryPasteTitle")}</h2>
          <button type="button" onClick={onClose} className="text-stone-400 hover:text-rose-400 transition"><X size={20} /></button>
        </div>
        <div className="px-6 py-4">
          <p className="text-xs text-stone-400 mb-3 leading-relaxed">{t("inventoryPasteDesc")}</p>
          <textarea
            value={text}
            onChange={(e) => setText(e.target.value)}
            placeholder={"A001\t25\nA002\t10\nA003\t8\n\n" + (lang === "zh" ? "（也可貼 3 欄：品牌／編號／數量）\nOPI\tB010\t14" : "(3 columns also works: Brand / Item No. / Qty)\nOPI\tB010\t14")}
            rows={10}
            className="w-full px-3 py-2.5 border border-stone-200 rounded-lg text-xs font-mono bg-stone-50 outline-none focus:border-rose-300 resize-none"
          />
          {text.trim() && (
            <div className="flex items-center gap-4 text-xs mt-2.5 text-stone-500">
              <span>{t("inventoryPasteMatched")}: <b className="text-stone-700">{parsed.rows.length}</b></span>
              {parsed.invalid > 0 && <span className="text-amber-500">{t("inventoryPasteInvalid")}: {parsed.invalid}</span>}
            </div>
          )}
        </div>
        <div className="flex items-center gap-2 px-6 py-4 border-t border-stone-100">
          <button type="button" onClick={onClose} className="text-sm font-medium text-stone-500 border border-stone-200 hover:border-stone-300 px-4 py-2 rounded-lg transition ml-auto">
            {t("cancel")}
          </button>
          <button
            type="button" onClick={handleConfirm} disabled={!parsed.rows.length || submitting}
            className="text-sm font-medium bg-rose-400 hover:bg-rose-500 disabled:opacity-50 text-white px-4 py-2 rounded-lg transition"
          >
            {submitting ? t("guestSubmitting") : `${t("inventoryPasteConfirm")} (${parsed.rows.length})`}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ────────────────────────────────────────────────────
   INVENTORY USAGE REPORT (admin only)
   Simple date-range analytics on top of the append-only
   "inventoryMovements" log (see AppInner for how entries
   get written on every qty change). This is intentionally
   a lightweight read-only query tool — good enough for
   "how much did we use of X between date A and B" without
   needing a dedicated analytics backend.
──────────────────────────────────────────────────── */

function InventoryUsageReport({ t, lang }) {
  const [open, setOpen] = useState(false);
  const [start, setStart] = useState(dateStr(-6));
  const [end, setEnd] = useState(todayStr());
  const [loading, setLoading] = useState(false);
  const [rows, setRows] = useState(null); // null = not run yet

  const quickRange = (kind) => {
    const now = new Date();
    if (kind === "today") { setStart(todayStr()); setEnd(todayStr()); }
    else if (kind === "7d") { setStart(dateStr(-6)); setEnd(todayStr()); }
    else if (kind === "30d") { setStart(dateStr(-29)); setEnd(todayStr()); }
    else if (kind === "month") {
      const first = new Date(now.getFullYear(), now.getMonth(), 1);
      setStart(localDateKey(first)); setEnd(todayStr());
    }
  };

  const runReport = async () => {
    setLoading(true);
    try {
      const q = query(
        collection(db, "inventoryMovements"),
        where("dateKey", ">=", start),
        where("dateKey", "<=", end)
      );
      const snap = await getDocs(q);
      const byItem = new Map();
      snap.docs.forEach((d) => {
        const m = d.data();
        const key = m.itemId || m.itemNo;
        if (!byItem.has(key)) {
          byItem.set(key, { itemNo: m.itemNo, brand: m.brand || "", used: 0, restocked: 0, net: 0 });
        }
        const agg = byItem.get(key);
        const delta = Number(m.delta) || 0;
        if (delta < 0) agg.used += -delta; else agg.restocked += delta;
        agg.net += delta;
      });
      const list = [...byItem.values()].sort((a, b) => b.used - a.used);
      setRows(list);
    } catch (err) {
      console.error("inventory usage report error:", err);
      setRows([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="mt-8 bg-white border border-stone-200 rounded-xl shadow-sm">
      <button type="button" onClick={() => setOpen((v) => !v)}
        className="w-full flex items-center justify-between px-5 py-4 text-left">
        <span className="font-display text-lg font-light text-stone-800">{t("inventoryUsageReport")}</span>
        {open ? <ChevronUp size={18} className="text-stone-400" /> : <ChevronDown size={18} className="text-stone-400" />}
      </button>
      {open && (
        <div className="px-5 pb-5 border-t border-stone-100 pt-4">
          <p className="text-xs text-stone-400 mb-3 leading-relaxed">{t("inventoryUsageDesc")}</p>
          <div className="flex flex-wrap items-end gap-2 mb-3">
            <GField label={t("inventoryStartDate")}>
              <input type="date" value={start} onChange={(e) => setStart(e.target.value)} className="ginput" />
            </GField>
            <GField label={t("inventoryEndDate")}>
              <input type="date" value={end} onChange={(e) => setEnd(e.target.value)} className="ginput" />
            </GField>
            <button type="button" onClick={runReport} disabled={loading}
              className="text-sm font-medium bg-rose-400 hover:bg-rose-500 disabled:opacity-60 text-white px-4 py-2.5 rounded-lg transition">
              {loading ? t("inventoryLoadingReport") : t("inventoryRunReport")}
            </button>
            <style>{`.ginput { padding:9px 12px; border:1px solid #E7E5E4; border-radius:8px; font-size:13px; background:#FAFAF9; outline:none; transition:border-color .15s; } .ginput:focus { border-color:#FB7185; background:white; }`}</style>
          </div>
          <div className="flex flex-wrap gap-1.5 mb-4">
            {[["today", t("inventoryQuickToday")], ["7d", t("inventoryQuick7")], ["month", t("inventoryQuickMonth")], ["30d", t("inventoryQuick30")]].map(([k, label]) => (
              <button key={k} type="button" onClick={() => quickRange(k)}
                className="text-[11px] font-medium px-2.5 py-1 rounded-full border border-stone-200 text-stone-500 hover:border-rose-300 hover:text-rose-500 transition">
                {label}
              </button>
            ))}
          </div>

          {rows === null ? null : rows.length === 0 ? (
            <div className="text-sm text-stone-400 py-6 text-center">{t("inventoryReportEmpty")}</div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="text-left text-[11px] text-stone-400 uppercase tracking-wide border-b border-stone-100">
                    <th className="py-2 pr-3 font-medium">{t("inventoryBrand")}</th>
                    <th className="py-2 pr-3 font-medium">{t("inventoryItemNo")}</th>
                    <th className="py-2 pr-3 font-medium text-right">{t("inventoryUsed")}</th>
                    <th className="py-2 pr-3 font-medium text-right">{t("inventoryRestocked")}</th>
                    <th className="py-2 pr-3 font-medium text-right">{t("inventoryNetChange")}</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((r) => (
                    <tr key={`${r.brand}-${r.itemNo}`} className="border-b border-stone-50">
                      <td className="py-2 pr-3 text-stone-500 text-xs">{r.brand || t("inventoryNoBrand")}</td>
                      <td className="py-2 pr-3 font-medium text-stone-800">{r.itemNo}</td>
                      <td className="py-2 pr-3 text-right text-rose-500 font-semibold">{r.used || "—"}</td>
                      <td className="py-2 pr-3 text-right text-green-600 font-semibold">{r.restocked || "—"}</td>
                      <td className={`py-2 pr-3 text-right font-semibold ${r.net < 0 ? "text-rose-500" : r.net > 0 ? "text-green-600" : "text-stone-400"}`}>
                        {r.net > 0 ? `+${r.net}` : r.net}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


/* ════════════════════════════════════════════════════
   ADMIN INTRO EDITOR (lives inside CalendarPage header as a small button)
   — shown as a separate small section at top of calendar when admin
════════════════════════════════════════════════════ */

function IntroEditor({ t, lang, introText, onSave }) {
  const [open, setOpen] = useState(false);
  const [zh, setZh] = useState(introText?.zh || "");
  const [en, setEn] = useState(introText?.en || "");

  useEffect(() => {
    setZh(introText?.zh || "");
    setEn(introText?.en || "");
  }, [introText]);

  const save = () => { onSave(zh, en); setOpen(false); };

  if (!open) {
    return (
      <button type="button" onClick={() => setOpen(true)}
        className="flex items-center gap-1.5 text-xs font-medium text-stone-400 hover:text-rose-400 border border-stone-200 hover:border-rose-200 px-3 py-1.5 rounded-lg transition">
        <Pencil size={12} /> {t("editIntro")}
      </button>
    );
  }
  return (
    <div className="bg-white border border-rose-200 rounded-xl p-4 shadow-sm w-full max-w-xl">
      <div className="text-xs font-semibold text-stone-500 mb-2">{t("editIntro")}</div>
      <textarea value={zh} onChange={(e) => setZh(e.target.value)} rows={3} className="w-full text-sm border border-stone-200 rounded-lg px-3 py-2 mb-2 focus:outline-none focus:border-rose-400 resize-none" placeholder="中文介紹詞" />
      <textarea value={en} onChange={(e) => setEn(e.target.value)} rows={3} className="w-full text-sm border border-stone-200 rounded-lg px-3 py-2 mb-3 focus:outline-none focus:border-rose-400 resize-none" placeholder="English introduction" />
      <div className="flex gap-2">
        <button type="button" onClick={save} className="bg-rose-400 hover:bg-rose-500 text-white text-xs font-medium px-3 py-1.5 rounded-lg transition">{t("saveIntro")}</button>
        <button type="button" onClick={() => setOpen(false)} className="text-xs text-stone-500 border border-stone-200 px-3 py-1.5 rounded-lg transition">{t("cancel")}</button>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════
   POS PAGE
   Staff + Admin can enter sales records.
   Admin can also open Payroll sub-panel.
   Pay week: Saturday → Friday
════════════════════════════════════════════════════ */

function POSPage({ t, lang, user, services, staffList, branchIdx, posRecords, onSubmit, onDelete, payrollSettings, onSavePayroll, showToast }) {
  const isAdmin = user.role === "admin";

  // POS entry form state
  const [stylist, setStylist] = useState("");
  const [serviceId, setServiceId] = useState("");
  const [customService, setCustomService] = useState("");
  const [amount, setAmount] = useState("");
  const [submitting, setSubmitting] = useState(false);

  // UI state
  const [showPayroll, setShowPayroll] = useState(false);

  // Date helpers
  const todayKey = new Date().toLocaleDateString("en-CA");
  const todayDisplay = new Date().toLocaleDateString(lang === "zh" ? "zh-TW" : "en-US", { weekday: "long", year: "numeric", month: "long", day: "numeric" });

  // All staff across both branches flattened & deduped
  const allStaff = [...new Set([...(staffList[0] || []), ...(staffList[1] || [])])];

  // Visible (non-hidden) services
  const visibleServices = services.filter((s) => !s.hidden);

  // Today's records
  const todayRecords = posRecords.filter((r) => r.dateKey === todayKey && (isAdmin || r.branch === branchIdx));
  const todayTotal = todayRecords.reduce((sum, r) => sum + (Number(r.amount) || 0), 0);

  // By-stylist summary for today
  const staffTotals = {};
  todayRecords.forEach((r) => {
    if (!staffTotals[r.stylist]) staffTotals[r.stylist] = { total: 0, items: [] };
    staffTotals[r.stylist].total += Number(r.amount) || 0;
    staffTotals[r.stylist].items.push(r);
  });

  const handleSubmit = async () => {
    if (!stylist) { showToast(t("posSelectRequired"), "warn"); return; }
    const svcLabel = serviceId
      ? (visibleServices.find((s) => s.id === serviceId)?.[lang === "zh" ? "nameZh" : "nameEn"] || serviceId)
      : customService.trim();
    if (!svcLabel) { showToast(t("posSelectRequired"), "warn"); return; }
    if (!amount || isNaN(Number(amount)) || Number(amount) <= 0) { showToast(t("posEnterAmount"), "warn"); return; }

    setSubmitting(true);
    const ok = await onSubmit({ stylist, service: svcLabel, amount: Number(amount), branch: branchIdx, enteredBy: user.username || user.displayName });
    if (ok) {
      showToast(t("posSubmitted"), "success");
      setServiceId(""); setCustomService(""); setAmount("");
    }
    setSubmitting(false);
  };

  const formatTime = (ts) => {
    if (!ts?.toDate) return "—";
    return ts.toDate().toLocaleTimeString(lang === "zh" ? "zh-TW" : "en-US", { hour: "2-digit", minute: "2-digit" });
  };

  return (
    <div>
      {/* Header */}
      <div className="flex items-center justify-between mb-1 flex-wrap gap-3">
        <div>
          <h1 className="font-display text-2xl md:text-3xl font-light text-stone-800">
            {lang === "zh" ? <>POS <span className="text-rose-400">收銀</span></> : <>Point of <span className="text-rose-400">Sale</span></>}
          </h1>
          <div className="text-sm text-stone-400 mt-0.5">{todayDisplay}</div>
        </div>
        {isAdmin && (
          <button
            type="button"
            onClick={() => setShowPayroll((v) => !v)}
            className={`flex items-center gap-1.5 text-sm font-medium px-4 py-2 rounded-lg border transition
              ${showPayroll ? "bg-stone-800 border-stone-700 text-white" : "border-stone-200 text-stone-600 hover:border-rose-300 hover:text-rose-500"}`}
          >
            <BarChart2 size={15} /> {t("navPayroll")}
            {showPayroll ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          </button>
        )}
      </div>

      {/* ── PAYROLL PANEL (admin only, collapsible) ── */}
      {isAdmin && showPayroll && (
        <PayrollPanel
          t={t} lang={lang}
          posRecords={posRecords}
          allStaff={allStaff}
          payrollSettings={payrollSettings}
          onSave={onSavePayroll}
          branchIdx={branchIdx}
          isAdmin={isAdmin}
        />
      )}

      <div className="grid lg:grid-cols-2 gap-5 mt-4">

        {/* ── LEFT: Entry form ── */}
        <div className="bg-white border border-stone-200 rounded-xl p-5 shadow-sm">
          <div className="text-sm font-semibold text-stone-700 mb-4 flex items-center gap-2">
            <ShoppingCart size={16} className="text-rose-400" />
            {lang === "zh" ? "新增紀錄" : "New Entry"}
          </div>

          <div className="space-y-3">
            {/* Stylist */}
            <div>
              <label className="text-xs font-medium text-stone-500 mb-1 block">{t("posStylist")} *</label>
              <select value={stylist} onChange={(e) => setStylist(e.target.value)} className="w-full px-3 py-2.5 text-sm border border-stone-200 rounded-lg bg-stone-50 focus:outline-none focus:border-rose-400 transition">
                <option value="">{t("posSelectStylist")}</option>
                {allStaff.map((s) => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>

            {/* Service — pick from list or type custom */}
            <div>
              <label className="text-xs font-medium text-stone-500 mb-1 block">{t("posService")} *</label>
              <select value={serviceId} onChange={(e) => { setServiceId(e.target.value); if (e.target.value) setCustomService(""); }} className="w-full px-3 py-2.5 text-sm border border-stone-200 rounded-lg bg-stone-50 focus:outline-none focus:border-rose-400 transition">
                <option value="">{t("posSelectService")}</option>
                {SERVICE_CATEGORIES.map((cat) => {
                  const items = visibleServices.filter((s) => s.cat === cat.id);
                  if (!items.length) return null;
                  return (
                    <optgroup key={cat.id} label={lang === "zh" ? cat.nameZh : cat.nameEn}>
                      {items.map((s) => (
                        <option key={s.id} value={s.id}>{lang === "zh" ? s.nameZh : s.nameEn}</option>
                      ))}
                    </optgroup>
                  );
                })}
              </select>
              <div className="text-[11px] text-stone-400 mt-1 mb-1">{lang === "zh" ? "或自訂：" : "Or custom:"}</div>
              <input
                value={customService}
                onChange={(e) => { setCustomService(e.target.value); if (e.target.value) setServiceId(""); }}
                placeholder={t("posCustomService")}
                className="w-full px-3 py-2 text-sm border border-stone-200 rounded-lg bg-stone-50 focus:outline-none focus:border-rose-400 transition"
              />
            </div>

            {/* Amount */}
            <div>
              <label className="text-xs font-medium text-stone-500 mb-1 block">{t("posAmount")} *</label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400 text-sm font-medium">₱</span>
                <input
                  type="number"
                  min="0"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  onKeyDown={(e) => { if (e.key === "Enter") handleSubmit(); }}
                  placeholder="0"
                  className="w-full pl-7 pr-3 py-2.5 text-sm border border-stone-200 rounded-lg bg-stone-50 focus:outline-none focus:border-rose-400 transition"
                />
              </div>
            </div>

            <button
              type="button"
              onClick={handleSubmit}
              disabled={submitting}
              className="w-full bg-rose-400 hover:bg-rose-500 disabled:opacity-60 text-white font-medium text-sm py-3 rounded-lg transition flex items-center justify-center gap-2"
            >
              <Receipt size={15} /> {submitting ? t("posSubmitting") : t("posSubmit")}
            </button>
          </div>
        </div>

        {/* ── RIGHT: Today's summary ── */}
        <div className="space-y-4">

          {/* Revenue cards */}
          <div className="grid grid-cols-2 gap-3">
            <div className="bg-rose-400 rounded-xl p-4 text-white">
              <div className="text-xs font-medium opacity-80 mb-1">{t("posTodayRevenue")}</div>
              <div className="font-display text-2xl font-light">₱{todayTotal.toLocaleString()}</div>
              <div className="text-xs opacity-70 mt-1">{todayRecords.length} {lang === "zh" ? "筆" : "entries"}</div>
            </div>
            <div className="bg-stone-800 rounded-xl p-4 text-white">
              <div className="text-xs font-medium opacity-80 mb-1">{t("posByStaff")}</div>
              <div className="text-xs space-y-0.5 mt-1">
                {Object.entries(staffTotals).map(([name, data]) => (
                  <div key={name} className="flex justify-between gap-2">
                    <span className="truncate opacity-80">{name}</span>
                    <span className="font-semibold flex-shrink-0">₱{data.total.toLocaleString()}</span>
                  </div>
                ))}
                {Object.keys(staffTotals).length === 0 && <div className="opacity-50">{t("posNoRecords")}</div>}
              </div>
            </div>
          </div>

          {/* Today's records list */}
          <div className="bg-white border border-stone-200 rounded-xl p-4 shadow-sm">
            <div className="text-sm font-semibold text-stone-700 mb-3">{t("posToday")}</div>
            {todayRecords.length === 0 ? (
              <div className="text-sm text-stone-400 py-4 text-center">{t("posNoRecords")}</div>
            ) : (
              <div className="space-y-1.5 max-h-80 overflow-y-auto">
                {[...todayRecords].reverse().map((r) => (
                  <div key={r.id} className="flex items-center gap-2 px-3 py-2 bg-stone-50 rounded-lg border border-stone-100 group">
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="text-xs font-semibold text-stone-700">{r.stylist}</span>
                        <span className="text-xs text-stone-500 truncate">{r.service}</span>
                      </div>
                      <div className="text-[11px] text-stone-400">{formatTime(r.recordedAt)}</div>
                    </div>
                    <span className="text-sm font-bold text-rose-400 flex-shrink-0">₱{Number(r.amount).toLocaleString()}</span>
                    {(isAdmin || r.enteredBy === (user.username || user.displayName)) && (
                      <button
                        onClick={() => { if (window.confirm(t("posDeleteRecord"))) onDelete(r.id); }}
                        className="opacity-0 group-hover:opacity-100 text-stone-300 hover:text-rose-400 transition p-1"
                      >
                        <Trash2 size={13} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════
   PAYROLL PANEL (admin sub-panel inside POS)
   Pay week: Saturday → Friday
════════════════════════════════════════════════════ */

function PayrollPanel({ t, lang, posRecords, allStaff, payrollSettings, onSave, branchIdx, isAdmin }) {
  // Current pay week bounds (Sat–Fri)
  const getPayWeek = (offsetWeeks = 0) => {
    const today = new Date();
    const dayOfWeek = today.getDay(); // 0=Sun...6=Sat
    // Days since last Saturday
    const sinceSat = (dayOfWeek + 1) % 7;
    const sat = new Date(today);
    sat.setDate(today.getDate() - sinceSat + offsetWeeks * 7);
    sat.setHours(0, 0, 0, 0);
    const fri = new Date(sat);
    fri.setDate(sat.getDate() + 6);
    fri.setHours(23, 59, 59, 999);
    return { sat, fri };
  };

  const [weekOffset, setWeekOffset] = useState(0);
  const { sat, fri } = getPayWeek(weekOffset);
  const satKey = sat.toLocaleDateString("en-CA");
  const friKey = fri.toLocaleDateString("en-CA");

  // Draft payroll settings (editable locally, saved on button press)
  const [draft, setDraft] = useState(() => {
    const d = {};
    allStaff.forEach((name) => {
      d[name] = {
        commission: payrollSettings[name]?.commission ?? 30,
        base: payrollSettings[name]?.base ?? 0,
      };
    });
    return d;
  });

  // Keep draft in sync when settings load from Firestore
  useEffect(() => {
    setDraft((prev) => {
      const next = { ...prev };
      allStaff.forEach((name) => {
        if (!next[name]) next[name] = { commission: payrollSettings[name]?.commission ?? 30, base: payrollSettings[name]?.base ?? 0 };
        else {
          next[name].commission = payrollSettings[name]?.commission ?? next[name].commission;
          next[name].base = payrollSettings[name]?.base ?? next[name].base;
        }
      });
      return next;
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [payrollSettings]);

  // Filter records for the selected pay week
  const weekRecords = posRecords.filter((r) => r.dateKey >= satKey && r.dateKey <= friKey && (isAdmin || r.branch === branchIdx));

  // Per-staff revenue
  const staffRevenue = {};
  weekRecords.forEach((r) => {
    if (!staffRevenue[r.stylist]) staffRevenue[r.stylist] = 0;
    staffRevenue[r.stylist] += Number(r.amount) || 0;
  });

  const totalRevenue = weekRecords.reduce((s, r) => s + (Number(r.amount) || 0), 0);

  const setStaffDraft = (name, field, val) => {
    setDraft((prev) => ({ ...prev, [name]: { ...prev[name], [field]: Number(val) || 0 } }));
  };

  const weekLabel = () => {
    const opts = { month: "short", day: "numeric" };
    return `${sat.toLocaleDateString(lang === "zh" ? "zh-TW" : "en-US", opts)} – ${fri.toLocaleDateString(lang === "zh" ? "zh-TW" : "en-US", opts)}`;
  };

  return (
    <div className="bg-stone-900 text-white rounded-xl p-5 mt-4 space-y-4">
      {/* Week nav */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <div className="text-sm font-semibold">{t("payrollTitle")}</div>
          <div className="text-xs text-stone-400 mt-0.5">{t("payrollWeek")}: {weekLabel()}</div>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setWeekOffset((w) => w - 1)} className="p-1.5 rounded-lg bg-stone-700 hover:bg-stone-600 transition"><ChevronLeft size={16} /></button>
          <button onClick={() => setWeekOffset(0)} className="text-xs px-3 py-1.5 rounded-lg bg-stone-700 hover:bg-stone-600 transition">
            {lang === "zh" ? "本週" : "This week"}
          </button>
          <button onClick={() => setWeekOffset((w) => w + 1)} className="p-1.5 rounded-lg bg-stone-700 hover:bg-stone-600 transition"><ChevronRight size={16} /></button>
        </div>
      </div>

      {/* Total */}
      <div className="flex items-center justify-between bg-stone-800 rounded-xl px-4 py-3">
        <span className="text-sm text-stone-300">{t("payrollRevenue")}</span>
        <span className="font-display text-xl font-light text-rose-300">₱{totalRevenue.toLocaleString()}</span>
      </div>

      {/* Per-staff breakdown */}
      {allStaff.length === 0 ? (
        <div className="text-sm text-stone-400 text-center py-4">{t("posNoRecords")}</div>
      ) : (
        <div className="space-y-3">
          {allStaff.map((name) => {
            const rev = staffRevenue[name] || 0;
            const settings = draft[name] || { commission: 30, base: 0 };
            const commAmt = Math.round(rev * settings.commission / 100);
            const total = commAmt + settings.base;
            return (
              <div key={name} className="bg-stone-800 rounded-xl p-4">
                <div className="flex items-center justify-between mb-3">
                  <span className="font-semibold text-sm">{name}</span>
                  <span className="text-rose-300 font-semibold">₱{total.toLocaleString()}</span>
                </div>
                <div className="grid grid-cols-3 gap-2 mb-2">
                  <div className="text-center">
                    <div className="text-[10px] text-stone-400 mb-1">{t("payrollRevenue")}</div>
                    <div className="text-sm font-medium">₱{rev.toLocaleString()}</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[10px] text-stone-400 mb-1">{t("payrollCommissionAmt")}</div>
                    <div className="text-sm font-medium text-amber-300">₱{commAmt.toLocaleString()}</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[10px] text-stone-400 mb-1">{t("payrollBaseSalary")}</div>
                    <div className="text-sm font-medium">₱{settings.base.toLocaleString()}</div>
                  </div>
                </div>
                {/* Editable settings inline */}
                <div className="flex gap-2 mt-2">
                  <div className="flex-1">
                    <div className="text-[10px] text-stone-400 mb-1">{t("payrollCommission")} (%)</div>
                    <input
                      type="number" min="0" max="100"
                      value={settings.commission}
                      onChange={(e) => setStaffDraft(name, "commission", e.target.value)}
                      className="w-full px-2 py-1.5 text-xs bg-stone-700 border border-stone-600 rounded-lg text-white focus:outline-none focus:border-rose-400"
                    />
                  </div>
                  <div className="flex-1">
                    <div className="text-[10px] text-stone-400 mb-1">{t("payrollBase")} (₱)</div>
                    <input
                      type="number" min="0"
                      value={settings.base}
                      onChange={(e) => setStaffDraft(name, "base", e.target.value)}
                      className="w-full px-2 py-1.5 text-xs bg-stone-700 border border-stone-600 rounded-lg text-white focus:outline-none focus:border-rose-400"
                    />
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Save settings */}
      <button
        type="button"
        onClick={() => onSave(draft)}
        className="w-full bg-rose-400 hover:bg-rose-500 text-white text-sm font-medium py-2.5 rounded-lg transition flex items-center justify-center gap-2"
      >
        <Settings size={14} /> {t("payrollSaveSettings")}
      </button>
    </div>
  );
}

function FirestoreTestPage({ t, lang, showToast }) {
  const [text, setText] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);

  // Real-time listener — list updates instantly on any change, no manual refetch needed.
  useEffect(() => {
    const q = query(collection(db, "messages"), orderBy("createdAt", "desc"));
    const unsubscribe = onSnapshot(
      q,
      (snap) => {
        setMessages(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
        setLoading(false);
      },
      (err) => {
        console.error(err);
        showToast(t("fetchError"), "warn");
        setLoading(false);
      }
    );
    return () => unsubscribe();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSend = async () => {
    if (sending) return; // prevent double-submit
    if (!text.trim()) {
      showToast(t("messageEmpty"), "warn");
      return;
    }
    const value = text.trim();
    setSending(true);
    try {
      await addDoc(collection(db, "messages"), {
        text: value,
        createdAt: serverTimestamp(),
      });
      setText("");
      showToast(t("messageSaved"), "success");
    } catch (err) {
      console.error(err);
      showToast(t("messageError"), "warn");
    } finally {
      setSending(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") handleSend();
  };

  const formatTimestamp = (ts) => {
    if (!ts?.toDate) return "—";
    return ts.toDate().toLocaleString(lang === "zh" ? "zh-TW" : "en-US");
  };

  return (
    <div>
      <h1
        className="font-display text-2xl md:text-3xl font-light text-stone-800 mb-2"
        dangerouslySetInnerHTML={{ __html: t("firestoreTitle") }}
      />
      <p className="text-sm text-stone-500 mb-5">{t("firestoreDesc")}</p>

      {/* Input + submit */}
      <div className="bg-white border border-stone-200 rounded-xl p-5 shadow-sm mb-6">
        <div className="flex gap-2">
          <input
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={t("messagePlaceholder")}
            className="flex-1 px-3 py-2.5 text-sm border border-stone-200 rounded-lg bg-stone-50 focus:outline-none focus:border-rose-400 focus:bg-white transition"
          />
          <button
            type="button"
            onClick={handleSend}
            disabled={sending}
            className="flex items-center gap-1.5 bg-rose-400 hover:bg-rose-500 disabled:opacity-60 text-white text-sm font-medium px-4 py-2.5 rounded-lg transition flex-shrink-0"
          >
            <Send size={15} /> {sending ? t("sending") : t("sendMessage")}
          </button>
        </div>
      </div>

      {/* Current messages — synced live from Firestore */}
      <div className="bg-white border border-stone-200 rounded-xl p-5 shadow-sm">
        <div className="flex items-center justify-between pb-2.5 border-b border-stone-100 mb-3">
          <h3 className="font-display text-lg font-light text-stone-800">{t("allMessages")}</h3>
          <span className="flex items-center gap-1.5 text-xs font-medium text-stone-400">
            <RefreshCw size={13} className={loading ? "animate-spin" : ""} /> {loading ? t("loadingMessages") : t("liveSync")}
          </span>
        </div>
        {loading ? (
          <div className="text-sm text-stone-400 py-3">{t("loadingMessages")}</div>
        ) : messages.length === 0 ? (
          <div className="text-sm text-stone-400 py-3">{t("noMessages")}</div>
        ) : (
          <div className="space-y-2">
            {messages.map((m) => (
              <div key={m.id} className="flex items-center justify-between gap-3 bg-stone-50 border border-stone-100 rounded-lg px-3 py-2.5">
                <span className="text-sm text-stone-800 break-words">{m.text}</span>
                <span className="text-[11px] text-stone-400 flex-shrink-0">{formatTimestamp(m.createdAt)}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}


